import { NextResponse } from 'next/server';
import { readFile } from 'fs/promises';
import path from 'path';

/**
 * GET /api/eval/results
 *
 * Returns the evaluation summary data (summary.json) containing
 * P/R/F1 metrics for each extractor across all branches.
 *
 * Data source: eval/reports/baseline/summary.json (static, generated by Promptfoo runs)
 */
export async function GET() {
  try {
    const filePath = path.join(process.cwd(), '..', 'eval', 'reports', 'baseline', 'summary.json');
    const raw = await readFile(filePath, 'utf-8');
    const data = JSON.parse(raw);
    return NextResponse.json(data);
  } catch (error) {
    return NextResponse.json(
      { error: 'Evaluation summary data not found' },
      { status: 404 }
    );
  }
}
